output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?player WHERE {
  wd:Q1084121 wdt:P587 ?player ; wdt:P586 ?draftYear ; wdt:P584 ?delistYear .
  FILTER(YEAR(?draftYear) = 1997 && YEAR(?delistYear) = 1998)
}

args.sparql:
SELECT ?player WHERE {
  wd:Q1084121 wdt:P587 ?player.
  ?player wdt:P586 ?draftYear.
  FILTER (YEAR(?draftYear) = 1998)
  ?player wdt:P584 ?delistYear.
  FILTER (YEAR(?delistYear) = 1998)
  OPTIONAL { ?player rdfs:label ?label. FILTER (lang(?label) = "en") }
}

SELECT ?player WHERE {
  ?player wdt:P19 wd:Q823531 .
